from pathlib import Path
import re

def normalize(s):
    s = str(s).strip()
    s = re.sub(r'[\u2013\u2014]', '-', s)  # en/em-dash → hyphen
    s = re.sub(r'\s+', ' ', s)
    return s.lower()

def val_matches(col_key, actual, expected):
    """Timezone-tolerant comparison: slack evidence accepted with or without tz suffix."""
    a, e = normalize(actual), normalize(expected)
    if a == e:
        return True
    if col_key == 'slack evidence':
        e_no_tz = re.sub(r'\s+(est|edt|cst|cdt|mst|mdt|pst|pdt|utc|gmt)$', '', e)
        return a == e_no_tz
    return False

def verify(workspace_path, external_services_path=None):
    ws = Path(workspace_path)
    spreadsheet_files = (list(ws.glob('**/*.xlsx')) +
                         list(ws.glob('**/*.xls')))

    if not spreadsheet_files:
        return {"pass": False, "score": 0.0,
                "feedback": "No spreadsheet file found in workspace"}

    wire_id = 'INTL-2026-0147'

    # Expected values for agent-filled audit columns (pre-normalized)
    expected = {
        'slack evidence':            '2026-03-04, 10:00 am est',
        'approver 1 name':           'karen stills',
        'approver 1 title':          'vp, treasury operations',
        'approver 1 text':           'approved.',
        'approver 2 name':           'michael drury',
        'approver 2 title':          'svp, finance & risk',
        'approver 2 text':           'approved.',
        'dual auth confirmed (y/n)': 'y',
        'exception code applied':    '',
    }

    row_found = False
    checks_passed = []
    checks_failed = []

    for fpath in spreadsheet_files:
        try:
            if str(fpath).lower().endswith(('.xlsx', '.xls')):
                import openpyxl
                wb = openpyxl.load_workbook(str(fpath), data_only=True)
                for sheet in wb.sheetnames:
                    ws_sheet = wb[sheet]
                    all_rows = list(ws_sheet.iter_rows(values_only=True))
                    if len(all_rows) < 4:
                        continue
                    # Row 3 (index 2) = headers, data from row 4 (index 3)
                    headers = [str(c).strip() if c else '' for c in all_rows[2]]
                    for r in all_rows[3:]:
                        cells = [str(c) if c is not None else '' for c in r]
                        row_dict = dict(zip(headers, cells))
                        wire_val = next(
                            (v for k, v in row_dict.items() if normalize(k) == 'wire id'), ''
                        )
                        if normalize(wire_val) != normalize(wire_id):
                            continue
                        row_found = True
                        for col_key, exp_val in expected.items():
                            actual_val = next(
                                (v for k, v in row_dict.items() if normalize(k) == col_key), None
                            )
                            if actual_val is None:
                                checks_failed.append(f"column '{col_key}' not found in headers")
                                continue
                            if val_matches(col_key, actual_val, exp_val):
                                checks_passed.append(col_key)
                            else:
                                checks_failed.append(
                                    f"'{col_key}': expected '{exp_val}', got '{actual_val}'"
                                )
        except Exception:
            continue

    if not row_found:
        return {"pass": False, "score": 0.0,
                "feedback": f"{wire_id} not found in any workbook. "
                            f"Files scanned: {[str(f) for f in spreadsheet_files]}"}

    total = len(expected)
    passed = len(checks_passed)
    score = round(passed / total, 4)

    if checks_failed:
        return {"pass": False, "score": score,
                "feedback": f"{wire_id}: {passed}/{total} checks passed. "
                            f"Failures: {checks_failed}"}
    return {"pass": True, "score": 1.0,
            "feedback": f"{wire_id}: all {total} audit column checks passed."}

