from pathlib import Path
import json
import re


def normalize(s):
    s = str(s).strip()
    s = re.sub(r'[–—]', '-', s)
    s = re.sub(r'\s+', ' ', s)
    return s.lower()


def extract_text(node):
    """Recursively extract plain text from a Jira doc object or return string as-is."""
    if isinstance(node, str):
        return node
    if isinstance(node, dict):
        if node.get('type') == 'text':
            return node.get('text', '')
        return ' '.join(extract_text(child) for child in node.get('content', []))
    if isinstance(node, list):
        return ' '.join(extract_text(item) for item in node)
    return str(node)


def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0,
                "feedback": "external_services_path is None; cannot check Jira state"}

    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found"}

    with open(jira_path, encoding='utf-8') as f:
        data = json.load(f)

    issues = data.get("issues", {})
    all_comments = data.get("comments", {})

    target_keys = ['OPS-2', 'OPS-5']
    # SOP 3.3 Happy path: dual-auth confirmation is recorded by adding a comment
    # that includes the exact token below. (A status change is not representable in
    # the Jira workflow, so verification lives in a comment.) Matched exactly and
    # case-sensitively so the token is stable for any downstream consumer.
    expected_token = 'status=verified'
    checks_passed = []
    checks_failed = []

    for key in target_keys:
        issue = issues.get(key)
        if issue is None:
            checks_failed.append(f"{key}: not found in jira_state.json")
            checks_failed.append(f"{key}: verification-comment check skipped (issue missing)")
            checks_failed.append(f"{key}: not-escalated check skipped (issue missing)")
            continue

        comments = all_comments.get(key, [])
        comments = comments if isinstance(comments, list) else []
        bodies = [extract_text(c.get('body', '') if isinstance(c, dict) else c) for c in comments]

        # Check 1: a comment carries the exact verification token 'status=verified'
        if any(expected_token in b for b in bodies):
            checks_passed.append(f"{key}: has comment containing '{expected_token}'")
        else:
            checks_failed.append(
                f"{key}: no comment contains exact token '{expected_token}'. Comments: {bodies}")

        # Check 2: a verified wire must NOT be escalated (no TRE-900 exception comment)
        if not any('tre-900' in normalize(b) for b in bodies):
            checks_passed.append(f"{key}: not escalated (no TRE-900 comment)")
        else:
            checks_failed.append(
                f"{key}: has a TRE-900 escalation comment; a verified wire must not be escalated. "
                f"Comments: {bodies}")

    total = len(target_keys) * 2  # verification-comment + not-escalated, per wire
    passed = len(checks_passed)
    score = round(passed / total, 4)

    if checks_failed:
        return {"pass": False, "score": score,
                "feedback": f"{passed}/{total} checks passed. Failures: {checks_failed}"}
    return {"pass": True, "score": 1.0,
            "feedback": "Both OPS-2 and OPS-5 "
                        "carry a 'status=verified' comment and were not escalated."}

from pathlib import Path
import json
import re

def normalize(s):
    s = str(s).strip()
    s = re.sub(r'[\u2013\u2014]', '-', s)
    s = re.sub(r'\s+', ' ', s)
    return s.lower()

def extract_text(node):
    """Recursively extract plain text from a Jira doc object or return string as-is."""
    if isinstance(node, str):
        return node
    if isinstance(node, dict):
        if node.get('type') == 'text':
            return node.get('text', '')
        return ' '.join(extract_text(child) for child in node.get('content', []))
    if isinstance(node, list):
        return ' '.join(extract_text(item) for item in node)
    return str(node)

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0,
                "feedback": "external_services_path is None; cannot check Jira state"}

    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found"}

    with open(jira_path, encoding='utf-8') as f:
        data = json.load(f)

    issues = data.get("issues", {})
    all_comments = data.get("comments", {})

    target_keys = ['OPS-3', 'OPS-4']
    expected_comment = 'TRE-900 High-Risk Exception'
    checks_passed = []
    checks_failed = []

    for key in target_keys:
        issue = issues.get(key)
        if issue is None:
            checks_failed.append(f"{key}: not found in jira_state.json")
            checks_failed.append(f"{key}: comment count check skipped (issue missing)")
            checks_failed.append(f"{key}: comment text check skipped (issue missing)")
            continue

        # Status check
        status = issue.get('fields', {}).get('status', {}).get('name', '')
        if status.lower() == 'open':
            checks_passed.append(f"{key}: status='{status}'")
        else:
            checks_failed.append(f"{key}: status='{status}', expected 'Open'")

        # Comment count check
        comments = all_comments.get(key, [])
        comments = comments if isinstance(comments, list) else []
        if len(comments) == 1:
            checks_passed.append(f"{key}: comment count=1")
        else:
            checks_failed.append(f"{key}: {len(comments)} comment(s), expected exactly 1")

        # Comment text check
        if len(comments) == 1:
            raw = comments[0].get('body', '') if isinstance(comments[0], dict) else comments[0]
            body = extract_text(raw)
            if normalize(body) == normalize(expected_comment):
                checks_passed.append(f"{key}: comment text matches")
            else:
                checks_failed.append(
                    f"{key}: comment text expected '{expected_comment}', got '{body}'"
                )
        else:
            checks_failed.append(f"{key}: comment text check skipped (wrong count)")

    total = len(target_keys) * 3  # status + count + text per wire
    passed = len(checks_passed)
    score = round(passed / total, 4)

    if checks_failed:
        return {"pass": False, "score": score,
                "feedback": f"{passed}/{total} checks passed. Failures: {checks_failed}"}
    return {"pass": True, "score": 1.0,
            "feedback": f"Both OPS-3 and OPS-4 "
                        f"are Open with exactly 1 comment: '{expected_comment}'."}

