def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0,
                "feedback": "external_services_path is None; cannot check Slack data"}

    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}

    with open(slack_path, encoding='utf-8') as f:
        data = json.load(f)

    # Resolve #compliance-urgent by name
    channels = data.get("channels", {})
    compliance_id = next(
        (cid for cid, info in channels.items()
         if isinstance(info, dict) and info.get('name') == 'compliance-urgent'),
        None
    )
    if compliance_id is None:
        return {"pass": False, "score": 0.0,
                "feedback": "Channel #compliance-urgent not found in slack_data.json"}

    channel_msgs = data.get("messages", {}).get(compliance_id, [])
    if not isinstance(channel_msgs, list):
        channel_msgs = []

    # Gate: exactly 2 messages required
    if len(channel_msgs) != 2:
        return {"pass": False, "score": 0.0,
                "feedback": f"#compliance-urgent has {len(channel_msgs)} message(s), expected exactly 2"}

    expected_texts = [
        "Compliance International wire control exception filed - Jira: OPS-7 | Wire ID: INTL-2026-0151 | OPS-3 | Junior Operations Analyst",
        "Compliance International wire control exception filed - Jira: OPS-8 | Wire ID: INTL-2026-0158 | OPS-4 | Junior Operations Analyst",
    ]

    actual_texts = [str(m.get('text', '')) for m in channel_msgs]
    checks_passed = []
    checks_failed = []

    for exp in expected_texts:
        exp_norm = normalize(exp)
        match = next((a for a in actual_texts if normalize(a) == exp_norm), None)
        if match is not None:
            checks_passed.append(exp)
        else:
            checks_failed.append(
                f"Expected message not found: '{exp}'. "
                f"Actual messages: {actual_texts}"
            )

    total = len(expected_texts)
    passed = len(checks_passed)
    score = round(passed / total, 4)

    if checks_failed:
        return {"pass": False, "score": score,
                "feedback": f"{passed}/{total} messages matched. Failures: {checks_failed}"}
    return {"pass": True, "score": 1.0,
            "feedback": "Both expected #compliance-urgent messages found with exact content."}

