from pathlib import Path
import json
import openpyxl


def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0,
                "feedback": "external_services_path is None; cannot check external service files"}

    feedback_parts = []
    all_pass = True
    total_checks = 5
    passed_checks = 0

    # ---- Check 1: jira_state.json has exactly 8 issues ----
    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        feedback_parts.append("FAIL [Check 1]: jira_state.json not found.")
        all_pass = False
    else:
        try:
            with open(jira_path, "r", encoding="utf-8") as f:
                jira_data = json.load(f)
            issues = jira_data.get("issues", {})
            issue_count = len(issues)
            if issue_count == 8:
                feedback_parts.append("PASS [Check 1]: jira_state.json has exactly 8 issues.")
                passed_checks += 1
            else:
                feedback_parts.append(f"FAIL [Check 1]: jira_state.json has {issue_count} issues, expected 8. "
                                       f"Keys: {list(issues.keys())}")
                all_pass = False
        except Exception as e:
            feedback_parts.append(f"FAIL [Check 1]: Error reading jira_state.json: {e}")
            all_pass = False

    # ---- Check 2: slack_data.json channel message counts ----
    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        feedback_parts.append("FAIL [Check 2]: slack_data.json not found.")
        all_pass = False
    else:
        try:
            with open(slack_path, "r", encoding="utf-8") as f:
                slack_data = json.load(f)

            messages = slack_data.get("messages", {})
            channels = slack_data.get("channels", {})

            treasury_id = next(
                (cid for cid, info in channels.items()
                 if isinstance(info, dict) and info.get("name") == "treasury-wires"), None
            )
            compliance_id = next(
                (cid for cid, info in channels.items()
                 if isinstance(info, dict) and info.get("name") == "compliance-urgent"), None
            )

            c001_count = len(messages.get(treasury_id, [])) if treasury_id else None
            c002_count = len(messages.get(compliance_id, [])) if compliance_id else None

            c2_pass = True
            if c001_count is None:
                feedback_parts.append("FAIL [Check 2a]: treasury-wires channel not found.")
                all_pass = False; c2_pass = False
            elif c001_count != 11:
                feedback_parts.append(f"FAIL [Check 2a]: treasury-wires has {c001_count} messages, expected 11.")
                all_pass = False; c2_pass = False
            else:
                feedback_parts.append("PASS [Check 2a]: treasury-wires has exactly 11 messages.")

            if c002_count is None:
                feedback_parts.append("FAIL [Check 2b]: compliance-urgent channel not found.")
                all_pass = False; c2_pass = False
            elif c002_count != 2:
                feedback_parts.append(f"FAIL [Check 2b]: compliance-urgent has {c002_count} messages, expected 2.")
                all_pass = False; c2_pass = False
            else:
                feedback_parts.append("PASS [Check 2b]: compliance-urgent has exactly 2 messages.")

            if c2_pass:
                passed_checks += 1
        except Exception as e:
            feedback_parts.append(f"FAIL [Check 2]: Error reading slack_data.json: {e}")
            all_pass = False

    # ---- Check 3: mailbox.json has 0 emails in Sent, Draft, Trash ----
    mail_path = Path(external_services_path) / "mailbox.json"
    if not mail_path.exists():
        feedback_parts.append("FAIL [Check 3]: mailbox.json not found.")
        all_pass = False
    else:
        try:
            with open(mail_path, "r", encoding="utf-8") as f:
                mail_data = json.load(f)
            emails = mail_data.get("emails", [])
            sent_count = sum(1 for e in emails if str(e.get("folder", "")).lower() == "sent")
            draft_count = sum(1 for e in emails if str(e.get("folder", "")).lower() in ("draft", "drafts"))
            trash_count = sum(1 for e in emails if str(e.get("folder", "")).lower() == "trash")
            if sent_count == 0 and draft_count == 0 and trash_count == 0:
                feedback_parts.append("PASS [Check 3]: mailbox.json has 0 Sent, 0 Draft, 0 Trash emails.")
                passed_checks += 1
            else:
                feedback_parts.append(f"FAIL [Check 3]: Sent={sent_count}, Draft={draft_count}, "
                                       f"Trash={trash_count}; expected all 0.")
                all_pass = False
        except Exception as e:
            feedback_parts.append(f"FAIL [Check 3]: Error reading mailbox.json: {e}")
            all_pass = False

    # ---- Check 4: calendar_data.json has exactly 3 events ----
    cal_path = Path(external_services_path) / "calendar_data.json"
    if not cal_path.exists():
        feedback_parts.append("FAIL [Check 4]: calendar_data.json not found.")
        all_pass = False
    else:
        try:
            with open(cal_path, "r", encoding="utf-8") as f:
                cal_data = json.load(f)
            events = cal_data.get("events", [])
            event_count = len(events) if isinstance(events, list) else len(events)
            if event_count == 3:
                feedback_parts.append("PASS [Check 4]: calendar_data.json has exactly 3 events.")
                passed_checks += 1
            else:
                feedback_parts.append(f"FAIL [Check 4]: calendar_data.json has {event_count} events, expected 3.")
                all_pass = False
        except Exception as e:
            feedback_parts.append(f"FAIL [Check 4]: Error reading calendar_data.json: {e}")
            all_pass = False

    # ---- Check 5: Wire_Population_Q1_2026.xlsx has exactly 7 non-empty rows ----
    xlsx_path = Path(workspace_path) / "Wire_Population_Q1_2026.xlsx"
    if not xlsx_path.exists():
        found = list(Path(workspace_path).rglob("Wire_Population_Q1_2026.xlsx"))
        if found:
            xlsx_path = found[0]

    if not xlsx_path.exists():
        feedback_parts.append("FAIL [Check 5]: Wire_Population_Q1_2026.xlsx not found in workspace.")
        all_pass = False
    else:
        try:
            wb = openpyxl.load_workbook(xlsx_path, data_only=True)
            target_sheet = next(
                (wb[name] for name in wb.sheetnames
                 if "wire population" in name.lower() and "q1" in name.lower()),
                wb[wb.sheetnames[0]]
            )
            total_rows = sum(
                1 for row in target_sheet.iter_rows(min_row=1, max_row=target_sheet.max_row)
                if any(cell.value is not None for cell in row)
            )
            if total_rows == 7:
                feedback_parts.append("PASS [Check 5]: Wire_Population_Q1_2026.xlsx has exactly 7 rows (3 header + 4 data).")
                passed_checks += 1
            else:
                feedback_parts.append(f"FAIL [Check 5]: Wire_Population_Q1_2026.xlsx has {total_rows} non-empty rows, expected 7.")
                all_pass = False
            wb.close()
        except Exception as e:
            feedback_parts.append(f"FAIL [Check 5]: Error reading Wire_Population_Q1_2026.xlsx: {e}")
            all_pass = False

    score = round(passed_checks / total_checks, 4)
    return {
        "pass": all_pass,
        "score": score,
        "feedback": "\n".join(feedback_parts)
    }
